Here's a toy implementation of a relational database query planner that converts SQL AST into a graph of relational algebra operations. The implementation includes AST nodes, relational algebra operators, and a planner that builds an operator graph.

```python
from abc import ABC, abstractmethod
from typing import List, Dict, Any, Optional

# AST Nodes
class ASTNode(ABC):
    @abstractmethod
    def accept(self, visitor):
        pass

class SelectNode(ASTNode):
    def __init__(self, columns: List[str], from_table: str, where_clause: Optional[ASTNode] = None):
        self.columns = columns
        self.from_table = from_table
        self.where_clause = where_clause

    def accept(self, visitor):
        return visitor.visit_select(self)

class WhereNode(ASTNode):
    def __init__(self, condition: ASTNode):
        self.condition = condition

    def accept(self, visitor):
        return visitor.visit_where(self)

class ConditionNode(ASTNode):
    def __init__(self, left: str, operator: str, right: Any):
        self.left = left
        self.operator = operator
        self.right = right

    def accept(self, visitor):
        return visitor.visit_condition(self)

# Relational Algebra Operators
class RelationalOperator(ABC):
    def __init__(self, name: str):
        self.name = name
        self.inputs: List[RelationalOperator] = []

    @abstractmethod
    def execute(self):
        pass

class Scan(RelationalOperator):
    def __init__(self, table_name: str):
        super().__init__("Scan")
        self.table_name = table_name

    def execute(self):
        return f"Scan({self.table_name})"

class Projection(RelationalOperator):
    def __init__(self, columns: List[str]):
        super().__init__("Projection")
        self.columns = columns

    def execute(self):
        return f"Projection({', '.join(self.columns)})"

class Selection(RelationalOperator):
    def __init__(self, condition: str):
        super().__init__("Selection")
        self.condition = condition

    def execute(self):
        return f"Selection({self.condition})"

# Query Planner
class QueryPlanner:
    def __init__(self):
        self.operators: List[RelationalOperator] = []

    def plan(self, ast: ASTNode) -> List[RelationalOperator]:
        self.operators = []
        root_operator = ast.accept(self)
        self._build_graph(root_operator)
        return self.operators

    def _build_graph(self, operator: RelationalOperator):
        if not operator.inputs:
            self.operators.append(operator)
        else:
            for input_op in operator.inputs:
                self._build_graph(input_op)
            self.operators.append(operator)

    def visit_select(self, node: SelectNode) -> RelationalOperator:
        scan = Scan(node.from_table)

        if node.where_clause:
            where_operator = node.where_clause.accept(self)
            where_operator.inputs.append(scan)
            return where_operator
        else:
            return scan

    def visit_where(self, node: WhereNode) -> RelationalOperator:
        condition = node.condition.accept(self)
        selection = Selection(condition)
        return selection

    def visit_condition(self, node: ConditionNode) -> str:
        return f"{node.left} {node.operator} {node.right}"

# Usage Example
def main():
    # Create AST for: SELECT name, age FROM users WHERE age > 18
    condition = ConditionNode("age", ">", 18)
    where = WhereNode(condition)
    select = SelectNode(["name", "age"], "users", where)

    # Plan the query
    planner = QueryPlanner()
    operators = planner.plan(select)

    # Print operators in execution order (bottom-up)
    print("Relational Algebra Operators (execution order):")
    for i, op in enumerate(operators):
        print(f"{i+1}. {op.execute()}")

    # Visualize the operator graph
    print("\nOperator Graph (tree representation):")
    for op in operators:
        if op.inputs:
            input_names = [inp.execute() for inp in op.inputs]
            print(f"{op.execute()} ← {', '.join(input_names)}")
        else:
            print(f"{op.execute()} (leaf)")

if __name__ == "__main__":
    main()
```

**How It Works:**

1. **AST Representation**: The SQL query is represented as an AST with `SelectNode`, `WhereNode`, and `ConditionNode`.

2. **Relational Algebra Operators**: 
   - `Scan`: Reads data from a table
   - `Selection`: Filters rows based on a condition (WHERE clause)
   - `Projection`: Selects specific columns

3. **Query Planner**: 
   - Traverses the AST using the Visitor pattern
   - Builds a graph of operators where lower-level operators (like Scan) are inputs to higher-level ones (like Selection)
   - The `_build_graph` method ensures operators are collected in bottom-up order

4. **Example Output**:
   ```
   Relational Algebra Operators (execution order):
   1. Scan(users)
   2. Selection(age > 18)

   Operator Graph (tree representation):
   Scan(users) (leaf)
   Selection(age > 18) ← Scan(users)
   ```

**Key Design Decisions:**
- The planner assumes a simple pipeline: Scan → Selection (if WHERE exists) → Projection
- In a real database, projection would be included, but this example focuses on the WHERE clause transformation
- The operator graph represents data flow from leaves (Scan) to root (final operator)

**Extensions You Could Add:**
1. Add `Projection` operator for column selection
2. Support multiple conditions with AND/OR
3. Add join operations
4. Implement actual execution with in-memory data structures

This toy implementation demonstrates the core concept of converting SQL to relational algebra, which is fundamental to real database query planners.

