    const input = inputs[0];
    const output = outputs[0];

    if (!input || !input.length || !output || !output.length) {
      return true;
    }

    // Update sample rate if changed
    if (sampleRate !== this.previousSampleRate) {
      this.sampleRate = sampleRate;
      this.delayBufferLength = Math.floor(this.sampleRate); // 1 second
      this.delayBuffer = new Float32Array(this.delayBufferLength);
      this.writeIndex = 0;
      this.previousSampleRate = this.sampleRate;
    }

    const delayValues = parameters.delay;
    const depthValues = parameters.depth;
    const rateValues = parameters.rate;
    const mixValues = parameters.mix;

    const isDelayConstant = delayValues.length === 1;
    const isDepthConstant = depthValues.length === 1;
    const isRateConstant = rateValues.length === 1;
    const isMixConstant = mixValues.length === 1;

    const blockSize = output[0].length;

    for (let sample = 0; sample < blockSize; sample++) {
      // Get parameter values for this sample
      const delayTime = isDelayConstant ? delayValues[0] : delayValues[sample];
      const depth = isDepthConstant ? depthValues[0] : depthValues[sample];
      const rate = isRateConstant ? rateValues[0] : rateValues[sample];
      const mix = isMixConstant ? mixValues[0] : mixValues[sample];

      // Update LFO phase
      this.lfoPhase += (2 * Math.PI * rate) / this.sampleRate;
      if (this.lfoPhase >= 2 * Math.PI) {
        this.lfoPhase -= 2 * Math.PI;
      }

      // Calculate modulated delay
      const lfoValue = Math.sin(this.lfoPhase);
      const modulatedDelay = delayTime + depth * lfoValue;
      const delaySamples = modulatedDelay * this.sampleRate;

      // Process each channel
      for (let channel = 0; channel < input.length; channel++) {
        const inputSample = input[channel][sample];

        // Write to delay buffer
        this.delayBuffer[this.writeIndex] = inputSample;

        // Read from delay buffer with linear interpolation
        let readIndex = this.writeIndex - delaySamples;
        if (readIndex < 0) {
          readIndex += this.delayBufferLength;
        }

        const readIndexFloor = Math.floor(readIndex);
        const readIndexCeil = (readIndexFloor + 1) % this.delayBufferLength;
        const fraction = readIndex - readIndexFloor;

        const delayedSample = this.delayBuffer[readIndexFloor] * (1 - fraction) + 
                             this.delayBuffer[readIndexCeil] * fraction;

        // Mix dry and wet signals
        output[channel][sample] = inputSample * (1 - mix) + delayedSample * mix;
      }

      // Update write index
      this.writeIndex = (this.writeIndex + 1) % this.delayBufferLength;
    }

    return true;
  }
}

