Here's a comprehensive Laravel controller for file uploads with best practices:

```php
<?php

namespace App\Http\Controllers;

use Illuminate\Http\Request;
use Illuminate\Http\JsonResponse;
use Illuminate\Support\Facades\Storage;
use Illuminate\Support\Str;

class FileUploadController extends Controller
{
    /**
     * Handle single file upload
     */
    public function uploadSingle(Request $request): JsonResponse
    {
        try {
            // Validate the uploaded file
            $validated = $request->validate([
                'file' => 'required|file|mimes:jpg,jpeg,png,pdf,doc,docx,txt|max:5120' // 5MB max
            ]);

            // Get the original file
            $file = $request->file('file');

            // Generate unique filename with original extension
            $originalName = $file->getClientOriginalName();
            $extension = $file->getClientOriginalExtension();
            $filename = Str::random(20) . '_' . time() . '.' . $extension;

            // Store file in storage/app/public/uploads directory
            $path = $file->storeAs('public/uploads', $filename);

            // Remove 'public/' from path for URL generation
            $relativePath = str_replace('public/', '', $path);

            return response()->json([
                'success' => true,
                'message' => 'File uploaded successfully',
                'data' => [
                    'original_name' => $originalName,
                    'filename' => $filename,
                    'path' => $path,
                    'url' => Storage::url($relativePath),
                    'size' => $file->getSize(),
                    'mime_type' => $file->getMimeType()
                ]
            ]);

        } catch (\Illuminate\Validation\ValidationException $e) {
            return response()->json([
                'success' => false,
                'message' => 'Validation failed',
                'errors' => $e->errors()
            ], 422);

        } catch (\Exception $e) {
            return response()->json([
                'success' => false,
                'message' => 'File upload failed',
                'error' => $e->getMessage()
            ], 500);
        }
    }

    /**
     * Handle multiple file uploads
     */
    public function uploadMultiple(Request $request): JsonResponse
    {
        try {
            // Validate multiple files
            $validated = $request->validate([
                'files' => 'required|array',
                'files.*' => 'required|file|mimes:jpg,jpeg,png,pdf,doc,docx,txt|max:5120'
            ]);

            $uploadedFiles = [];

            foreach ($request->file('files') as $file) {
                // Generate unique filename for each file
                $originalName = $file->getClientOriginalName();
                $extension = $file->getClientOriginalExtension();
                $filename = Str::random(20) . '_' . time() . '_' . uniqid() . '.' . $extension;

                // Store file
                $path = $file->storeAs('public/uploads', $filename);
                $relativePath = str_replace('public/', '', $path);

                $uploadedFiles[] = [
                    'original_name' => $originalName,
                    'filename' => $filename,
                    'path' => $path,
                    'url' => Storage::url($relativePath),
                    'size' => $file->getSize(),
                    'mime_type' => $file->getMimeType()
                ];
            }

            return response()->json([
                'success' => true,
                'message' => count($uploadedFiles) . ' file(s) uploaded successfully',
                'data' => $uploadedFiles
            ]);

        } catch (\Illuminate\Validation\ValidationException $e) {
            return response()->json([
                'success' => false,
                'message' => 'Validation failed',
                'errors' => $e->errors()
            ], 422);

        } catch (\Exception $e) {
            return response()->json([
                'success' => false,
                'message' => 'File upload failed',
                'error' => $e->getMessage()
            ], 500);
        }
    }

    /**
     * Delete uploaded file
     */
    public function deleteFile(Request $request): JsonResponse
    {
        try {
            $validated = $request->validate([
                'filename' => 'required|string'
            ]);

            $filename = $request->input('filename');
            $path = 'public/uploads/' . $filename;

            if (Storage::exists($path)) {
                Storage::delete($path);

                return response()->json([
                    'success' => true,
                    'message' => 'File deleted successfully'
                ]);
            }

            return response()->json([
                'success' => false,
                'message' => 'File not found'
            ], 404);

        } catch (\Exception $e) {
            return response()->json([
                'success' => false,
                'message' => 'File deletion failed',
                'error' => $e->getMessage()
            ], 500);
        }
    }
}
